/**
 * Menu Module Events
 *
 * Event definitions and emitters for the Menu module.
 * Provides typed domain events for menu, category, product, and related operations.
 *
 * @module modules/menu/menu.events
 *
 * @example
 * ```typescript
 * import { MenuEvents, emitMenuCreated } from '@/modules/menu/menu.events';
 *
 * // Emit a menu created event
 * await emitMenuCreated(eventService, {
 *   menuId: 'menu_123',
 *   organizationId: 'org_456',
 *   name: 'Lunch Menu',
 *   createdBy: 'user_789',
 * });
 * ```
 */

import type { EventService } from '@/core/services/event.service';

// -----------------------------------------------------------------------------
// Menu Event Types
// -----------------------------------------------------------------------------

/**
 * Base event payload with common fields
 */
export interface BaseEventPayload {
  /** Organization ID */
  organizationId: string;
  /** Event timestamp */
  timestamp: string;
  /** User who triggered the event */
  triggeredBy?: string;
}

/**
 * Menu created event payload
 */
export interface MenuCreatedEventPayload extends BaseEventPayload {
  /** Menu ID */
  menuId: string;
  /** Menu name */
  name: string;
  /** Created by user ID */
  createdBy?: string;
  /** Duplicated from menu ID (if applicable) */
  duplicatedFrom?: string;
}

/**
 * Menu updated event payload
 */
export interface MenuUpdatedEventPayload extends BaseEventPayload {
  /** Menu ID */
  menuId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Menu deleted event payload
 */
export interface MenuDeletedEventPayload extends BaseEventPayload {
  /** Menu ID */
  menuId: string;
  /** Menu name (for logging) */
  name: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

/**
 * Menu restored event payload
 */
export interface MenuRestoredEventPayload extends BaseEventPayload {
  /** Menu ID */
  menuId: string;
  /** Menu name */
  name: string;
  /** Restored by user ID */
  restoredBy?: string;
}

/**
 * Menu published event payload
 */
export interface MenuPublishedEventPayload extends BaseEventPayload {
  /** Menu ID */
  menuId: string;
  /** Publish timestamp */
  publishedAt: string;
  /** Whether QR code was generated */
  qrCodeGenerated: boolean;
  /** Published by user ID */
  publishedBy?: string;
}

/**
 * Menu unpublished event payload
 */
export interface MenuUnpublishedEventPayload extends BaseEventPayload {
  /** Menu ID */
  menuId: string;
  /** Unpublished by user ID */
  unpublishedBy?: string;
}

/**
 * Menu settings updated event payload
 */
export interface MenuSettingsUpdatedEventPayload extends BaseEventPayload {
  /** Menu ID */
  menuId: string;
  /** Previous settings */
  previousSettings: Record<string, unknown>;
  /** New settings */
  newSettings: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

// -----------------------------------------------------------------------------
// Category Event Types
// -----------------------------------------------------------------------------

/**
 * Category created event payload
 */
export interface CategoryCreatedEventPayload extends BaseEventPayload {
  /** Category ID */
  categoryId: string;
  /** Menu ID */
  menuId: string;
  /** Category name */
  name: string;
  /** Parent category ID (if nested) */
  parentId?: string;
  /** Created by user ID */
  createdBy?: string;
}

/**
 * Category updated event payload
 */
export interface CategoryUpdatedEventPayload extends BaseEventPayload {
  /** Category ID */
  categoryId: string;
  /** Menu ID */
  menuId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Category deleted event payload
 */
export interface CategoryDeletedEventPayload extends BaseEventPayload {
  /** Category ID */
  categoryId: string;
  /** Menu ID */
  menuId: string;
  /** Category name */
  name: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

/**
 * Category reordered event payload
 */
export interface CategoryReorderedEventPayload extends BaseEventPayload {
  /** Menu ID */
  menuId: string;
  /** Reordered items with new positions */
  items: Array<{ id: string; sortOrder: number }>;
  /** Reordered by user ID */
  reorderedBy?: string;
}

// -----------------------------------------------------------------------------
// Product Event Types
// -----------------------------------------------------------------------------

/**
 * Product created event payload
 */
export interface ProductCreatedEventPayload extends BaseEventPayload {
  /** Product ID */
  productId: string;
  /** Category ID */
  categoryId: string;
  /** Product name */
  name: string;
  /** Created by user ID */
  createdBy?: string;
}

/**
 * Product updated event payload
 */
export interface ProductUpdatedEventPayload extends BaseEventPayload {
  /** Product ID */
  productId: string;
  /** Category ID */
  categoryId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Product deleted event payload
 */
export interface ProductDeletedEventPayload extends BaseEventPayload {
  /** Product ID */
  productId: string;
  /** Category ID */
  categoryId: string;
  /** Product name */
  name: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

/**
 * Product availability changed event payload
 */
export interface ProductAvailabilityChangedEventPayload extends BaseEventPayload {
  /** Product ID */
  productId: string;
  /** Previous availability status */
  previousAvailability: boolean;
  /** New availability status */
  newAvailability: boolean;
  /** Changed by user ID */
  changedBy?: string;
}

/**
 * Products reordered event payload
 */
export interface ProductsReorderedEventPayload extends BaseEventPayload {
  /** Category ID */
  categoryId: string;
  /** Reordered items with new positions */
  items: Array<{ id: string; sortOrder: number }>;
  /** Reordered by user ID */
  reorderedBy?: string;
}

// -----------------------------------------------------------------------------
// Variant Event Types
// -----------------------------------------------------------------------------

/**
 * Variant created event payload
 */
export interface VariantCreatedEventPayload extends BaseEventPayload {
  /** Variant ID */
  variantId: string;
  /** Product ID */
  productId: string;
  /** Variant name */
  name: string;
  /** Created by user ID */
  createdBy?: string;
}

/**
 * Variant updated event payload
 */
export interface VariantUpdatedEventPayload extends BaseEventPayload {
  /** Variant ID */
  variantId: string;
  /** Product ID */
  productId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Variant deleted event payload
 */
export interface VariantDeletedEventPayload extends BaseEventPayload {
  /** Variant ID */
  variantId: string;
  /** Product ID */
  productId: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

// -----------------------------------------------------------------------------
// Modifier Event Types
// -----------------------------------------------------------------------------

/**
 * Modifier created event payload
 */
export interface ModifierCreatedEventPayload extends BaseEventPayload {
  /** Modifier ID */
  modifierId: string;
  /** Product ID */
  productId: string;
  /** Modifier name */
  name: string;
  /** Created by user ID */
  createdBy?: string;
}

/**
 * Modifier updated event payload
 */
export interface ModifierUpdatedEventPayload extends BaseEventPayload {
  /** Modifier ID */
  modifierId: string;
  /** Product ID */
  productId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Modifier deleted event payload
 */
export interface ModifierDeletedEventPayload extends BaseEventPayload {
  /** Modifier ID */
  modifierId: string;
  /** Product ID */
  productId: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

// -----------------------------------------------------------------------------
// Theme Event Types
// -----------------------------------------------------------------------------

/**
 * Theme created event payload
 */
export interface ThemeCreatedEventPayload extends BaseEventPayload {
  /** Theme ID */
  themeId: string;
  /** Theme name */
  name: string;
  /** Created by user ID */
  createdBy?: string;
}

/**
 * Theme updated event payload
 */
export interface ThemeUpdatedEventPayload extends BaseEventPayload {
  /** Theme ID */
  themeId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Theme deleted event payload
 */
export interface ThemeDeletedEventPayload extends BaseEventPayload {
  /** Theme ID */
  themeId: string;
  /** Theme name */
  name: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

// -----------------------------------------------------------------------------
// Menu Events Map
// -----------------------------------------------------------------------------

/**
 * Menu module domain events map
 */
export interface MenuModuleEvents {
  // Menu events
  'menu.created': MenuCreatedEventPayload;
  'menu.updated': MenuUpdatedEventPayload;
  'menu.deleted': MenuDeletedEventPayload;
  'menu.restored': MenuRestoredEventPayload;
  'menu.published': MenuPublishedEventPayload;
  'menu.unpublished': MenuUnpublishedEventPayload;
  'menu.settings.updated': MenuSettingsUpdatedEventPayload;

  // Category events
  'category.created': CategoryCreatedEventPayload;
  'category.updated': CategoryUpdatedEventPayload;
  'category.deleted': CategoryDeletedEventPayload;
  'category.reordered': CategoryReorderedEventPayload;

  // Product events
  'product.created': ProductCreatedEventPayload;
  'product.updated': ProductUpdatedEventPayload;
  'product.deleted': ProductDeletedEventPayload;
  'product.availability.changed': ProductAvailabilityChangedEventPayload;
  'products.reordered': ProductsReorderedEventPayload;

  // Variant events
  'variant.created': VariantCreatedEventPayload;
  'variant.updated': VariantUpdatedEventPayload;
  'variant.deleted': VariantDeletedEventPayload;

  // Modifier events
  'modifier.created': ModifierCreatedEventPayload;
  'modifier.updated': ModifierUpdatedEventPayload;
  'modifier.deleted': ModifierDeletedEventPayload;

  // Theme events
  'theme.created': ThemeCreatedEventPayload;
  'theme.updated': ThemeUpdatedEventPayload;
  'theme.deleted': ThemeDeletedEventPayload;
}

/**
 * Menu module event names
 */
export type MenuModuleEventName = keyof MenuModuleEvents;

/**
 * All menu module event names as an array
 */
export const MENU_MODULE_EVENTS: MenuModuleEventName[] = [
  'menu.created',
  'menu.updated',
  'menu.deleted',
  'menu.restored',
  'menu.published',
  'menu.unpublished',
  'menu.settings.updated',
  'category.created',
  'category.updated',
  'category.deleted',
  'category.reordered',
  'product.created',
  'product.updated',
  'product.deleted',
  'product.availability.changed',
  'products.reordered',
  'variant.created',
  'variant.updated',
  'variant.deleted',
  'modifier.created',
  'modifier.updated',
  'modifier.deleted',
  'theme.created',
  'theme.updated',
  'theme.deleted',
];

// -----------------------------------------------------------------------------
// Event Emitter Helpers
// -----------------------------------------------------------------------------

/**
 * Helper function to create timestamp
 */
function timestamp(): string {
  return new Date().toISOString();
}

/**
 * Emits a menu created event
 */
export async function emitMenuCreated(
  eventService: EventService,
  payload: Omit<MenuCreatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('menu.created', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a menu updated event
 */
export async function emitMenuUpdated(
  eventService: EventService,
  payload: Omit<MenuUpdatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('menu.updated', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a menu deleted event
 */
export async function emitMenuDeleted(
  eventService: EventService,
  payload: Omit<MenuDeletedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('menu.deleted', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a menu published event
 */
export async function emitMenuPublished(
  eventService: EventService,
  payload: Omit<MenuPublishedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('menu.published', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a category created event
 */
export async function emitCategoryCreated(
  eventService: EventService,
  payload: Omit<CategoryCreatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('category.created', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a category reordered event
 */
export async function emitCategoryReordered(
  eventService: EventService,
  payload: Omit<CategoryReorderedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('category.reordered', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a product created event
 */
export async function emitProductCreated(
  eventService: EventService,
  payload: Omit<ProductCreatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('product.created', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a product availability changed event
 */
export async function emitProductAvailabilityChanged(
  eventService: EventService,
  payload: Omit<ProductAvailabilityChangedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('product.availability.changed', {
    ...payload,
    timestamp: timestamp(),
  });
}

// -----------------------------------------------------------------------------
// Export All Event Types
// -----------------------------------------------------------------------------

export type {
  BaseEventPayload,
  MenuCreatedEventPayload,
  MenuUpdatedEventPayload,
  MenuDeletedEventPayload,
  MenuRestoredEventPayload,
  MenuPublishedEventPayload,
  MenuUnpublishedEventPayload,
  MenuSettingsUpdatedEventPayload,
  CategoryCreatedEventPayload,
  CategoryUpdatedEventPayload,
  CategoryDeletedEventPayload,
  CategoryReorderedEventPayload,
  ProductCreatedEventPayload,
  ProductUpdatedEventPayload,
  ProductDeletedEventPayload,
  ProductAvailabilityChangedEventPayload,
  ProductsReorderedEventPayload,
  VariantCreatedEventPayload,
  VariantUpdatedEventPayload,
  VariantDeletedEventPayload,
  ModifierCreatedEventPayload,
  ModifierUpdatedEventPayload,
  ModifierDeletedEventPayload,
  ThemeCreatedEventPayload,
  ThemeUpdatedEventPayload,
  ThemeDeletedEventPayload,
};
